    // ── Privacy & Terms ──
    privacy_page_title: 'Personvernerklæring',
    privacy_last_updated: 'Sist oppdatert: 2. mars 2026',
    privacy_intro_title: 'Introduksjon',
    privacy_intro_p: 'Velkommen til Loop Marked. Vi respekterer ditt privatliv og er forpliktet til å beskytte dine personlige data. Denne personvernerklæringen forklarer hvordan vi samler inn, bruker, avslører og beskytter informasjonen din når du bruker vår mobilapplikasjon, nettside og relaterte tjenester.',
    privacy_info_title: 'Informasjon vi samler inn',
    privacy_info_p: 'For å gi deg våre markedsplasstjenester samler vi inn følgende typer informasjon:',
    privacy_info_l1: '<strong>Kontoinformasjon:</strong> Når du registrerer deg, samler vi inn e-postadressen din eller autentiseringstokener fra Apple/Google.',
    privacy_info_l2: '<strong>Profilinformasjon:</strong> Ditt valgte visningsnavn, profilbilde og biografi.',
    privacy_info_l3: '<strong>Plasseringsdata:</strong> For å vise deg lokale oppføringer, samler vi inn den nøyaktige eller omtrentlige plasseringen din når du bruker appen.',
    privacy_info_l4: '<strong>Brukerinnhold:</strong> Informasjon om varer du legger ut for salg, bilder du laster opp, meldinger du sender via chattesystemet vårt og anmeldelser du legger igjen til andre brukere.',
    privacy_info_l5: '<strong>Bruksdata:</strong> Informasjon om hvordan du samhandler med appen vår, inkludert enhetsidentifikatorer og krasjlogger for å forbedre appytelsen.',
    privacy_info_l6: '<strong>Transaksjonsdata:</strong> Informasjon knyttet til Lumo-saldoen din og kjøp i appen. (Betalingsbehandlingen håndteres sikkert av Apple; vi lagrer ikke kredittkortopplysningene dine).',
    privacy_use_title: 'Hvordan vi bruker informasjonen din',
    privacy_use_p: 'Vi bruker informasjonen vi samler inn til:',
    privacy_use_l1: 'Tilby, vedlikeholde og forbedre appen og tjenestene våre.',
    privacy_use_l2: 'Behandle transaksjoner og administrer Lumo-økonomibalansen din.',
    privacy_use_l3: 'Tilrettelegge for kommunikasjon mellom kjøpere og selgere.',
    privacy_use_l4: 'Bekreft kontoer og forbedre sikkerheten og sikkerheten til plattformen vår.',
    privacy_use_l5: 'Send støttemeldinger, oppdateringer og sikkerhetsvarsler.',
    privacy_use_l6: 'Gi personlig tilpasset, lokalt innhold og markedsplassoppføringer.',
    privacy_share_title: 'Hvordan vi deler informasjonen din',
    privacy_share_p: 'Vi selger ikke din personlige informasjon. Vi kan dele informasjonen din i følgende situasjoner:',
    privacy_share_l1: '<strong>Med andre brukere:</strong> Din profilinformasjon, oppføringer og anmeldelser er synlige for andre brukere på plattformen.',
    privacy_share_l2: '<strong>Tjenesteleverandører:</strong> Vi bruker tredjepartstjenester (som Supabase for databasehosting) for å betjene appen vår. Disse leverandørene har tilgang til informasjonen din kun for å utføre oppgaver på våre vegne og er forpliktet til ikke å avsløre eller bruke den til andre formål.',
    privacy_share_l3: '<strong>Juridiske krav:</strong> Vi kan avsløre informasjon hvis loven krever det eller som svar på gyldige forespørsler fra offentlige myndigheter.',
    privacy_retention_title: 'Oppbevaring og sletting av data',
    privacy_retention_p: 'Vi beholder din personlige informasjon så lenge kontoen din er aktiv eller etter behov for å tilby deg tjenester. Du kan slette kontoen din og tilhørende data når som helst direkte i appinnstillingene eller ved å kontakte supportteamet vårt via chat.',
    privacy_rights_title: 'Dine personvernrettigheter',
    privacy_rights_p: 'Avhengig av hvor du befinner deg, kan du ha rett til å få tilgang til, korrigere eller slette dine personlige data. Du kan administrere personvernvalgene dine i appinnstillingene, inkludert synlighetsbrytere for lommeboksaldoen din og annen spesifikk informasjon.',
    privacy_contact_title: 'Kontakt oss',
    privacy_contact_p: 'Hvis du har spørsmål eller kommentarer om denne personvernerklæringen, vennligst kontakt oss via supportchatten i appen eller på <a href="mailto:support@loopmarked.com">support@loopmarked.com</a>.',
    terms_page_title: 'Vilkår for bruk',
    terms_last_updated: 'Sist oppdatert: 2. mars 2026',
    terms_1_title: '1. Aksept av vilkår',
    terms_1_p: 'Ved å gå inn på eller bruke Loop Marked godtar du å være bundet av disse tjenestevilkårene. Hvis du ikke godtar noen del av disse vilkårene, kan du ikke bruke applikasjonen vår. Vi tilbyr en fellesskapsentrisk plattform for å kjøpe, selge og handle trygt.',
    terms_2_title: '2. Brukerkontoer',
    terms_2_p: 'For å bruke de fleste funksjonene til Loop Marked, må du registrere deg for en konto ved å bruke Apple- eller Google-pålogging. Du er ansvarlig for å opprettholde konfidensialiteten til kontoen din og for alle aktiviteter som skjer under kontoen din.',
    terms_2_l1: '<strong>Kvalifisering:</strong> Du må være minst 12 år gammel (eller minimumsalderen som kreves i landet ditt) for å bruke plattformen vår.',
    terms_2_l2: '<strong>Nøyaktighet:</strong> All informasjon du oppgir må være nøyaktig og oppdatert.',
    terms_2_l3: '<strong>Oppsigelse:</strong> Vi forbeholder oss retten til å suspendere eller avslutte kontoer som bryter disse vilkårene eller deltar i uredelig aktivitet.',
    terms_3_title: '3. Tillatt og forbudt oppførsel',
    terms_3_p: 'Loop Marked er eksplisitt designet for å fremme et trygt handelsøkosystem. Når du bruker våre tjenester, samtykker du <strong>ikke</strong> til å:',
    terms_3_l1: 'Legg ut varer som er ulovlige, forfalskede eller eksplisitt forbudt i henhold til lokale lover.',
    terms_3_l2: 'Engasjere seg i trakassering, hatytringer eller overgrep mot andre medlemmer av samfunnet.',
    terms_3_l3: 'Forsøk å manipulere Lumo-økonomien, henvisningssystemet eller merkesystemet gjennom kunstige midler eller botkontoer.',
    terms_3_l4: 'Spam markedsplassen eller legg ut villedende oppføringer.',
    terms_4_title: '4. Lumo-økonomien',
    terms_4_p: 'Loop Marked bruker en intern virtuell valuta kalt <strong>Lumo</strong> for å lette interaksjoner og premiumfunksjoner.',
    terms_4_l1: '<strong>Anskaffelse:</strong> Lumo kan tjenes gratis (via daglige bonuser eller belønninger) eller kjøpes via kjøp i app (håndteres av Apple App Store eller Google Play).',
